{
  "pattern": {
    "summary": "Fold sign-bit extraction through trunc-to-i1 into a signed-negative compare. If a value X of integer type iN is shifted right by exactly N-1 bits using either lshr or ashr, and that shifted result is truncated to i1, then the trunc is equivalent to `icmp slt X, 0`.",
    "match": {
      "root": "trunc",
      "source_shape": "(lshr X, C) or (ashr X, C)",
      "preconditions": [
        "X has integer scalar or integer vector type with element bitwidth N",
        "destination type of trunc is i1 or vector of i1 with matching lane count",
        "C is a constant integer or splat constant equal to N-1 for each lane",
        "The transform is use-independent; source shift may have other uses"
      ]
    },
    "rewrite": {
      "scalar": "trunc (shr X, N-1) to i1  ==>  icmp slt X, 0",
      "vector": "trunc (shr <Ty> X, splat(N-1)) to <M x i1>  ==>  icmp slt <Ty> X, zeroinitializer"
    },
    "notes": [
      "Accept both `lshr` and `ashr`; both place the original sign bit into bit 0 when shifted by N-1.",
      "Works for arbitrary integer widths, not just power-of-two widths.",
      "Preserves semantics even if the trunc carries flags like `nuw`; those flags are irrelevant after folding.",
      "This canonicalization often enables later folds of boolean logic/select patterns involving sign tests.",
      "Only exact top-bit shifts should fold. Positive tests below all use the exact shift amount."
    ]
